Classes are blueprints for creating objects.

**Class Definition:**
```cpp
class Car {
  public:
    string brand;
    string model;
    int year;

    void displayInfo() {
      cout << brand << " " << model << " (" << year << ")" << endl;
    }
};
```

**Creating Objects:**
```cpp
int main() {
  Car myCar;
  myCar.brand = "Toyota";
  myCar.model = "Camry";
  myCar.year = 2022;
  myCar.displayInfo();

  return 0;
}
```

**Member Functions:**
```cpp
class Rectangle {
  public:
    double width;
    double height;

    double area() {
      return width * height;
    }

    double perimeter() {
      return 2 * (width + height);
    }
};
```

**Class vs Object:**
- Class: Blueprint/template
- Object: Instance of a class

Special member functions for initialization and cleanup.

**Constructor:**
```cpp
class Car {
  public:
    string brand;
    string model;
    int year;

    // Constructor
    Car(string b, string m, int y) {
      brand = b;
      model = m;
      year = y;
    }

    void displayInfo() {
      cout << brand << " " << model << " (" << year << ")" << endl;
    }
};

int main() {
  Car myCar("Toyota", "Camry", 2022);
  myCar.displayInfo();
  return 0;
}
```

**Default Constructor:**
```cpp
class Car {
  public:
    string brand;
    string model;
    int year;

    Car() {  // Default constructor
      brand = "Unknown";
      model = "Unknown";
      year = 0;
    }
};
```

**Destructor:**
```cpp
class Car {
  public:
    Car() {
      cout << "Constructor called" << endl;
    }

    ~Car() {  // Destructor
      cout << "Destructor called" << endl;
    }
};
```

Control access to class members using access modifiers.

**Access Modifiers:**
```cpp
class BankAccount {
  private:    // Only accessible within class
    double balance;

  public:     // Accessible from anywhere
    BankAccount(double initialBalance) {
      balance = initialBalance;
    }

    void deposit(double amount) {
      if (amount > 0) {
        balance += amount;
      }
    }

    void withdraw(double amount) {
      if (amount > 0 && amount <= balance) {
        balance -= amount;
      }
    }

    double getBalance() {
      return balance;
    }

  protected:  // Accessible in derived classes
    string accountNumber;
};
```

**Getter and Setter Methods:**
```cpp
class Person {
  private:
    string name;
    int age;

  public:
    void setName(string n) {
      name = n;
    }

    string getName() {
      return name;
    }

    void setAge(int a) {
      if (a >= 0) {
        age = a;
      }
    }

    int getAge() {
      return age;
    }
};
```

Create new classes based on existing classes.

**Base and Derived Classes:**
```cpp
class Animal {
  public:
    void eat() {
      cout << "This animal eats food." << endl;
    }

    void sleep() {
      cout << "This animal sleeps." << endl;
    }
};

class Dog : public Animal {
  public:
    void bark() {
      cout << "The dog barks!" << endl;
    }
};

class Cat : public Animal {
  public:
    void meow() {
      cout << "The cat meows!" << endl;
    }
};

int main() {
  Dog myDog;
  myDog.eat();    // Inherited from Animal
  myDog.bark();   // Own method

  Cat myCat;
  myCat.sleep();  // Inherited from Animal
  myCat.meow();   // Own method

  return 0;
}
```

**Types of Inheritance:**
- Public: Public members remain public
- Protected: Public members become protected
- Private: Public members become private

Different classes can respond to the same method call differently.

**Virtual Functions:**
```cpp
class Animal {
  public:
    virtual void makeSound() {
      cout << "Some sound" << endl;
    }
};

class Dog : public Animal {
  public:
    void makeSound() override {
      cout << "Woof!" << endl;
    }
};

class Cat : public Animal {
  public:
    void makeSound() override {
      cout << "Meow!" << endl;
    }
};

int main() {
  Animal* myPet;
  Dog myDog;
  Cat myCat;

  myPet = &myDog;
  myPet->makeSound();  // Woof!

  myPet = &myCat;
  myPet->makeSound();  // Meow!

  return 0;
}
```

**Pure Virtual Functions (Abstract Class):**
```cpp
class Shape {
  public:
    virtual double area() = 0;  // Pure virtual
};

class Rectangle : public Shape {
  public:
    double width, height;

    double area() override {
      return width * height;
    }
};
```

The STL provides ready-to-use data structures and algorithms.

**Vectors (Dynamic Arrays):**
```cpp
#include <vector>
#include <algorithm>

using namespace std;

int main() {
  vector<int> numbers = {1, 2, 3, 4, 5};

  numbers.push_back(6);  // Add element
  numbers.pop_back();     // Remove last

  cout << numbers.size() << endl;  // 5
  cout << numbers[2] << endl;      // 3

  // Iterate
  for (int num : numbers) {
    cout << num << " ";
  }

  return 0;
}
```

**Maps (Key-Value Pairs):**
```cpp
#include <map>

int main() {
  map<string, int> ages;

  ages["Alice"] = 25;
  ages["Bob"] = 30;

  cout << ages["Alice"] << endl;  // 25

  // Iterate
  for (auto& pair : ages) {
    cout << pair.first << ": " << pair.second << endl;
  }

  return 0;
}
```

**Sets (Unique Elements):**
```cpp
#include <set>

int main() {
  set<int> numbers = {1, 2, 3, 2, 1};

  // Automatically removes duplicates
  // numbers = {1, 2, 3}

  numbers.insert(4);

  for (int num : numbers) {
    cout << num << " ";
  }

  return 0;
}
```

**Common Algorithms:**
```cpp
#include <algorithm>
#include <vector>

int main() {
  vector<int> numbers = {5, 2, 8, 1, 9};

  sort(numbers.begin(), numbers.end());  // Sort
  reverse(numbers.begin(), numbers.end());  // Reverse

  auto it = find(numbers.begin(), numbers.end(), 8);

  int count = count_if(numbers.begin(), numbers.end(), 
    [](int x) { return x > 5; });

  return 0;
}
```

Read from and write to files using C++ file streams.

**Writing to a File:**
```cpp
#include <fstream>
#include <iostream>

using namespace std;

int main() {
  ofstream outFile("output.txt");

  if (outFile.is_open()) {
    outFile << "Hello, World!" << endl;
    outFile << "This is a file." << endl;
    outFile.close();
  } else {
    cout << "Unable to open file" << endl;
  }

  return 0;
}
```

**Reading from a File:**
```cpp
#include <fstream>
#include <iostream>
#include <string>

using namespace std;

int main() {
  ifstream inFile("input.txt");
  string line;

  if (inFile.is_open()) {
    while (getline(inFile, line)) {
      cout << line << endl;
    }
    inFile.close();
  } else {
    cout << "Unable to open file" << endl;
  }

  return 0;
}
```

**Reading and Writing Binary Files:**
```cpp
#include <fstream>

int main() {
  // Write binary
  ofstream outFile("data.bin", ios::binary);
  int number = 42;
  outFile.write(reinterpret_cast<char*>(&number), sizeof(number));
  outFile.close();

  // Read binary
  ifstream inFile("data.bin", ios::binary);
  int readNumber;
  inFile.read(reinterpret_cast<char*>(&readNumber), sizeof(readNumber));
  inFile.close();

  return 0;
}
```

**File Modes:**
- `ios::in` - Open for reading
- `ios::out` - Open for writing
- `ios::app` - Append to file
- `ios::binary` - Binary mode
- `ios::ate` - Seek to end when opening
